CREATE TABLE IF NOT EXISTS `postal_code_ranges` (
	`id` int AUTO_INCREMENT NOT NULL,
	`regionId` int NOT NULL,
	`startCode` varchar(20) NOT NULL,
	`endCode` varchar(20) NOT NULL,
	`description` text,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `postal_code_ranges_id` PRIMARY KEY(`id`)
);
CREATE INDEX IF NOT EXISTS `regionId_idx` ON `postal_code_ranges` (`regionId`);
CREATE INDEX IF NOT EXISTS `startCode_idx` ON `postal_code_ranges` (`startCode`);

CREATE TABLE IF NOT EXISTS `partner_territories` (
	`id` int AUTO_INCREMENT NOT NULL,
	`partnerId` int NOT NULL,
	`regionId` int NOT NULL,
	`priority` int NOT NULL DEFAULT 1,
	`isExclusive` boolean NOT NULL DEFAULT false,
	`assignedAt` timestamp NOT NULL DEFAULT (now()),
	`assignedBy` int,
	`notes` text,
	CONSTRAINT `partner_territories_id` PRIMARY KEY(`id`),
	CONSTRAINT `unique_partner_region` UNIQUE(`partnerId`,`regionId`)
);
CREATE INDEX IF NOT EXISTS `partnerId_idx` ON `partner_territories` (`partnerId`);
CREATE INDEX IF NOT EXISTS `regionId_idx` ON `partner_territories` (`regionId`);

